String dbUrl = "jdbc:mysql://localhost:3306/test"; 
String dbUsername = "root"; 
String dbPassword = "root"; 
String table ="account_disable_checking";
String fn = "FirstName";
String empNo = "EmployeeNo";

try{

  Class.forName("com.mysql.cj.jdbc.Driver");
  connection = DriverManager.getConnection(dbUrl, dbUsername, dbPassword);


  String updateQuery="update %s set %s= ? where %s=?";

  updateQuery = String.format(updateQuery, table,fn,empNo); 

  preparedStatement = connection.prepareStatement(updateQuery);
  preparedStatement.setString(1, "Ragada");
  preparedStatement.setString(2, "1");

  int count = preparedStatement.executeUpdate();

  log.error(" update count  :  "+count);
}catch (SQLException e) {
  e.printStackTrace();
}finally {
  /* if (resultSet != null) {
    try {
      resultSet.close();
    } catch (SQLException e) {
      e.printStackTrace();
    }
  }*/
  if (preparedStatement != null) {
    try {
      preparedStatement.close();
    } catch (SQLException e) {
      e.printStackTrace();
    }
  }
  if (connection != null) {
    try {
      connection.close();
    } catch (SQLException e) {
      e.printStackTrace();
    }
  }
}

return "Mahesh Nattali";

